import {ignores} from "./linter/ignores.mjs";
import {javascript} from "./linter/javascript.mjs";
import {prettier} from "./linter/prettier.mjs";
import {react} from "./linter/react.mjs";
import {reactRefresh} from "./linter/react-refresh.mjs";
import {sortImports} from "./linter/sort-imports.mjs";
import {sortJsxProps} from "./linter/sort-jsx-props.mjs";
import {stylistic} from "./linter/stylistic.mjs";

// Flat config only processes `.js`/`.mjs`/`.cjs` by default. Each section
// declares its own `files` field where it needs to (e.g. JSX-only blocks
// like a11y or `sort-jsx-props`); sections without `files` apply globally.

export default [
  ...ignores,
  ...javascript,
  ...react,
  ...reactRefresh,
  ...sortImports,
  ...sortJsxProps,
  ...stylistic,
  ...prettier,
];

import js from "@eslint/js";
import globals from "globals";
import tseslint from "typescript-eslint";

// Non type-aware on purpose: no `parserOptions.project`, which would force
// a full TS program load on every lint pass.
export const javascript = tseslint.config({
  name: "appncy/javascript",
  files: ["**/*.{js,mjs,cjs,jsx,ts,mts,cts,tsx}"],
  extends: [js.configs.recommended, tseslint.configs.recommended],
  languageOptions: {
    ecmaVersion: "latest",
    sourceType: "module",
    globals: {...globals.browser, ...globals.serviceworker},
  },
  rules: {
    "no-console": ["warn", {allow: ["error"]}],
    "@typescript-eslint/no-unused-vars": [
      "warn",
      {
        args: "after-used",
        ignoreRestSiblings: false,
        argsIgnorePattern: "^_.*?$",
        caughtErrorsIgnorePattern: "^_.*?$",
      },
    ],
    "@typescript-eslint/no-unsafe-member-access": "off",
    "@typescript-eslint/no-confusing-void-expression": "off",
    "@typescript-eslint/ban-ts-comment": "off",
    "@typescript-eslint/no-explicit-any": "off",
    "@typescript-eslint/no-inferrable-types": "off",
    "@typescript-eslint/no-non-null-assertion": "off",
    // Optionals
    // "@typescript-eslint/no-floating-promises": "off",
  },
});

import prettierRecommended from "eslint-plugin-prettier/recommended";

// Runs last so it overrides any stylistic rule still left on. Options are
// inlined with `usePrettierrc: false` so the plugin skips the per-file
// `prettier.resolveConfig` + `getFileInfo` calls that dominate its cost
// (see prettier/eslint-plugin-prettier#445).
export const prettier = [
  {
    ...prettierRecommended,
    name: "appncy/prettier",
    rules: {
      ...prettierRecommended.rules,
      "prettier/prettier": [
        "warn",
        {
          printWidth: 100,
          trailingComma: "all",
          tabWidth: 2,
          semi: true,
          singleQuote: false,
          bracketSpacing: false,
          arrowParens: "always",
          endOfLine: "auto",
          plugins: ["prettier-plugin-tailwindcss"],
        },
        {usePrettierrc: false},
      ],
    },
  },
];

import jsxA11y from "eslint-plugin-jsx-a11y";
import reactPlugin from "eslint-plugin-react";
import reactHooks from "eslint-plugin-react-hooks";
import tseslint from "typescript-eslint";

export const react = tseslint.config(
  {
    name: "appncy/react",
    extends: [
      reactPlugin.configs.flat.recommended,
      reactPlugin.configs.flat["jsx-runtime"],
      reactHooks.configs.flat.recommended,
    ],
    settings: {react: {version: "detect"}},
    rules: {
      "react/jsx-no-useless-fragment": "error",
      "react/self-closing-comp": "warn",
      "react/jsx-curly-brace-presence": ["error", {props: "never", children: "never"}],
    },
  },
  {
    name: "appncy/a11y",
    files: ["**/*.{jsx,tsx}"],
    extends: [jsxA11y.flatConfigs.recommended],
    rules: {
      "jsx-a11y/click-events-have-key-events": "off",
    },
  },
);

import refreshPlugin from "eslint-plugin-react-refresh";

// Vite/HMR-only: warns when a module exports something other than a
// component, which would break Fast Refresh.
export const reactRefresh = [
  {
    name: "appncy/react-refresh",
    files: ["**/*.{jsx,tsx}"],
    plugins: {"react-refresh": refreshPlugin},
    rules: {
      "react-refresh/only-export-components": ["warn", {allowConstantExport: true}],
    },
  },
];

import perfectionist from "eslint-plugin-perfectionist";

// Replaces eslint-plugin-import (`import/order`) with a faster, Map-based
// implementation.
export const sortImports = [
  {
    name: "appncy/sort-imports",
    plugins: {perfectionist},
    rules: {
      "perfectionist/sort-imports": [
        "warn",
        {
          type: "natural",
          order: "asc",
          newlinesBetween: 1,
          internalPattern: ["^@/.+", "^~/.+"],
          groups: [
            "type",
            "builtin",
            "external",
            "internal",
            ["parent", "sibling", "index"],
            "side-effect",
            "style",
            "unknown",
          ],
        },
      ],
      "perfectionist/sort-named-imports": ["warn", {type: "natural", order: "asc"}],
    },
  },
];

import perfectionist from "eslint-plugin-perfectionist";

// Replaces `react/jsx-sort-props` (perfectionist/react recommend disabling
// the react rule to avoid double-sorting).
export const sortJsxProps = [
  {
    name: "appncy/sort-jsx-props",
    files: ["**/*.{jsx,tsx}"],
    plugins: {perfectionist},
    rules: {
      "perfectionist/sort-jsx-props": [
        "warn",
        {
          type: "natural",
          order: "asc",
          groups: ["shorthand-prop", "multiline-prop", "unknown", "callback"],
          customGroups: [{groupName: "callback", elementNamePattern: "^on[A-Z].*"}],
        },
      ],
    },
  },
];

import stylisticPlugin from "@stylistic/eslint-plugin";

// `padding-line-between-statements` was removed from ESLint core's flat
// defaults; @stylistic is the supported home for it now.
export const stylistic = [
  {
    name: "appncy/stylistic",
    plugins: {"@stylistic": stylisticPlugin},
    rules: {
      "@stylistic/padding-line-between-statements": [
        "warn",
        {blankLine: "always", prev: "*", next: ["return", "export"]},
        {blankLine: "always", prev: ["const", "let", "var"], next: "*"},
        {blankLine: "any", prev: ["const", "let", "var"], next: ["const", "let", "var"]},
      ],
    },
  },
];
